it('should deliver notifications in order when events are emitted sequentially', async () => {
  /** Adapter that records delivery order and introduces async delay. */
  class DelayedAdapter implements NotificationAdapter {
    readonly channel = 'email' as const;
    deliveryOrder: string[] = [];
    private callCount = 0;

    async send(payload: NotificationPayload): Promise<NotificationResult> {
      const index = this.callCount++;
      // First call takes longer than second to expose ordering bugs
      const delay = index === 0 ? 50 : 10;
      await new Promise((resolve) => setTimeout(resolve, delay));
      this.deliveryOrder.push(payload.type);
      return { success: true };
    }
  }

  const delayedAdapter = new DelayedAdapter();
  const freshBus = new EventBus();
  const freshService = new NotificationService(freshBus);
  freshService.registerAdapter(delayedAdapter);

  const orderCreatedEvent: OrderCreatedEvent = {
    type: 'order:created',
    order: {
      id: 'order-1',
      userId: 'user-1',
      items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
      total: 10,
      status: 'pending',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    user: {
      id: 'user-1',
      name: 'Alice',
      email: 'alice@example.com',
      role: 'member',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    timestamp: new Date(),
  };

  const statusChangedEvent: OrderStatusChangedEvent = {
    type: 'order:status-changed',
    order: {
      id: 'order-1',
      userId: 'user-1',
      items: [],
      total: 10,
      status: 'confirmed',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    previousStatus: 'pending',
    newStatus: 'confirmed',
    timestamp: new Date(),
  };

  // Emit both events sequentially — order:created first, then status change
  await freshBus.emit(orderCreatedEvent);
  await freshBus.emit(statusChangedEvent);

  // Notifications must be delivered in the same order they were emitted
  expect(delayedAdapter.deliveryOrder).toEqual([
    'order:confirmation',
    'order:status-update',
  ]);
});

